gh api graphql -f query='
query {
  organization(login: "trilogy-group") {
    projectV2(number: 699) {
      id
      title
      items(first: 100) {
        totalCount
        nodes {
          id
          content {
            ... on Issue {
              number
              title
              state
              repository {
                nameWithOwner
              }
            }
            ... on PullRequest {
              number
              title
              state
              repository {
                nameWithOwner
              }
            }
          }
        }
        pageInfo {
          hasNextPage
          endCursor
        }
      }
    }
  }
}' 2>&1

